var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"DIRECTOR_SWANSONG_NPC_NULL","text":{"KOREA":"지금 아주 좋아요, 스완 양.","JPN":"いい感じです、スワンさん。","ENG":"Very well, Miss Swan.","TWN":"現在非常好，史旺。"},"stage":{"bg":"STREET_SPRING","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DIRECTOR_SWANSONG_NPC_NULL","text":{"KOREA":"마치 봄바람을 기다리고 있었던 것처럼, 설레는 느낌으로 부탁드릴게요.","JPN":"待ちわびた春風を迎えるように、ときめいている感じでお願いします。","ENG":"I will expect a heart fluttering performance as if waiting for a spring breeze.","TWN":"就像在等待春風一樣，請帶著激動的心情——"},"stage":{"bg":"STREET_SPRING","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DIRECTOR_SWANSONG_NPC_NULL","text":{"KOREA":"자아, 3번 카메라 레디. 4번 카메라 레디……!","JPN":"じゃあ！　カメラ3、カメラ4、レディー……！","ENG":"Now then, camera number 3, ready! Camera number 4, ready...!","TWN":"好了，3號攝影機準備。4號攝影機準備……！"},"stage":{"bg":"STREET_SPRING","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"오늘 촬영도 고생 많으셨어요, 스완님.","JPN":"今日の撮影もお疲れ様でした、スワンさん。","ENG":"Great work today, Miss Swan.","TWN":"今天拍攝也辛苦了，史旺。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"스폰서도 아주 만족하는 것 같아요. 벌써부터 전속모델 이야기가 들리는 것 같더라고요.","JPN":"スポンサーも大満足ですって。今から専属モデルの話も出ているらしいですよ。","ENG":"The sponsors are over the moon. I think they're already considering using you as their exclusive model.","TWN":"觀眾非常滿意。贊助商好像已經在談論專屬模特的事情了。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"고생 많았어, 스완. 오늘 무대도 반응이 아주 뜨겁던데?","JPN":"お疲れ様、スワン。今日の舞台もすごい盛り上がりだったわね。","ENG":"Great work, Swan. The audience's reactions were so enthusiastic.","TWN":"辛苦了，史旺。今天的舞台反應也很熱烈吧？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"네가 프리마돈나가 된 뒤로 극장 매출이 세 배 가까이 올랐지 뭐야?","JPN":"あなたがプリマドンナになってから、劇場の売り上げが三倍近く跳ね上がったのよ！","ENG":"Did you know that theater sales have nearly tripled since you became a prima donna?","TWN":"自從你成為首席女演員後，劇院的收入幾乎翻了三倍呢。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……매니저.","JPN":"……マネージャー。","ENG":"...Manager.","TWN":"……經紀人。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"호들갑 떨지 말고, 다음 일정이나 말해주세요.","JPN":"そんなことより、次のスケジュールを確認してください。","ENG":"Stop making a fuss and tell me my next schedule.","TWN":"別大驚小怪的，告訴我下一個行程吧。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"아, 네! 잠시만요! 어디 보자…….","JPN":"あ、はい！　お待ちください、えっと……","ENG":"Oh, right! Hold on just a moment! Lemme see here...","TWN":"啊，是！等一下！讓我看看……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"3시에는 드라마 촬영이 있고, 다음에는 감독님과 미팅, 드라마 각본 공모전 검토…….","JPN":"3時からはドラマ撮影で、その後は監督と打ち合わせ、ドラマ脚本コンテストの検討……","ENG":"You have a drama filming at 3 o'clock, then a meeting with the director, reviewing the script for the contest...","TWN":"你3點有電視劇拍攝，然後是和導演的會議，討論電視劇劇本徵集的審查……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"7시 이후 스케줄은 전부 조정해 주세요.","JPN":"7時以降の予定はすべてリスケしてください。","ENG":"Rearrange all appointments scheduled for after 7 PM.","TWN":"請調整7點以後的所有日程。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"오늘은 G 스타디움에 가야 하니까요.","JPN":"今日はGスタジアムに行かないと。","ENG":"I must head to G Stadium today.","TWN":"我今天必須去一趟G體育場。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"네? G 스타디움이라고요? 리그를 관람하시게요?","JPN":"Gスタジアム……？　リーグを観戦されるのですか？","ENG":"Huh? G Stadium? Are you going to watch the game?","TWN":"是？G體育場？你要去觀看聯賽嗎？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"괜찮으시겠어요? 또 악질 기자들이 기를 쓰고 와일러랑 엮으려 들 텐데요?","JPN":"大丈夫でしょうか……またたちの悪い記者たちがワイラーと絡ませてくるかもしれませんよ？","ENG":"Are you sure? Those stupid reporters might start lumping you with that Wyler again.","TWN":"你確定嗎？那些惡劣的記者們肯定會拼命造謠你和瓦勒的關係。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"괜찮아요. 그런 스캔들은 익숙하니까요.","JPN":"大丈夫です。あんなスキャンダルは慣れています。","ENG":"It's fine. I'm used to scandals like that.","TWN":"沒關係。這種緋聞我已經習慣了。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 정말로 만나고 싶은 사람은 따로 있거든요.","JPN":"それに本当に会いたい人は別にいるので。","ENG":"There's somebody else that I really want to meet.","TWN":"而且我真正想見的另有其人。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"만나고 싶은 사람이라고요……?","JPN":"会いたい人ですか……？","ENG":"Someone you want to meet...?","TWN":"你說想見的人……？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"중요한 전화네요. 잠시 자리를 비우죠.","JPN":"大事な電話なので、少し席を外します。","ENG":"This is an important call. Could I have some privacy?","TWN":"是重要的電話。我暫時離開一下。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무슨 일이죠?","JPN":"何のご用ですか？","ENG":"What is it?","TWN":"什麼事？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"일하는 중이에요. 연락은 최대한 피해달라고 부탁드렸을 텐데요.","JPN":"仕事中です。連絡はなるべく避けるようお願いしたはずですが。","ENG":"I'm working. I remember insisting that we avoid contact as much as possible.","TWN":"我在工作。應該已經拜託過儘量不要聯繫我了。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};